class Endpaper:
    def __init__(self, pastedown_side, free_endpaper_side):
        self.pastedown_side = pastedown_side  # Attached to the inside cover
        self.free_endpaper_side = free_endpaper_side  # First free page

    def describe(self):
        return f"Pastedown: {self.pastedown_side}, Free Endpaper: {self.free_endpaper_side}"

# Example usage:
front_endpaper = Endpaper("Inside front cover", "First free page before title page")
print(front_endpaper.describe())
